hooks.command:
jq -r '.tool_input.file_path // .tool_input.filePath // empty' | { read -r f; echo "$f" | grep -qE 'shachotwo-app/(workers/micro|workers/bpo/common|llm/prompts)/.*\.py$' || exit 0; dir=$(dirname "$f"); fname=$(basename "$f" .py); existing=$(find "$dir" -maxdepth 1 -name '*.py' -not -name '__init__.py' -not -name "$fname.py" 2>/dev/null); [ -z "$existing" ] && exit 0; new_funcs=$(grep -oE 'def [a-zA-Z_][a-zA-Z0-9_]*' "$f" 2>/dev/null | sed 's/def //' | sort -u); [ -z "$new_funcs" ] && exit 0; dups=''; for ef in $existing; do for func in $new_funcs; do grep -q "def $func" "$ef" 2>/dev/null && dups="${dups}  - ${func}() already in $(basename $ef)
"; done; done; [ -z "$dups" ] && exit 0; printf '関数名重複検出:
%s既存実装の再利用を検討してください。' "$dups" >&2; exit 2; }

jq -r '.tool_input.file_path // .tool_input.filePath // empty' | { read -r f; echo "$f" | grep -qE 'shachotwo-app/frontend/.*\.tsx$' || exit 0; forbidden=$(grep -nE 'ダッシュボード|管理画面|登録する|送信する|削除する|model_used|session_id|cost_yen|gemini-2|claude-3|gpt-4' "$f" 2>/dev/null | head -5); [ -z "$forbidden" ] && exit 0; printf 'UI_RULES違反の可能性:
%s
UI_RULES.mdの禁止ワードを確認してください。' "$forbidden" >&2; exit 2; }
